&lt;ol&gt;
&lt;li&gt;路径后面添加？rewriteBatchedStatements=true 允许批量插入&lt;/li&gt;
&lt;li&gt;INSERT INTO … VALUES [必须写]&lt;/li&gt;
&lt;li&gt;不执行每条语句，批量添加 addBatch ()&lt;/li&gt;
&lt;li&gt;遍历添加完毕，统一批量执行 executeBatch ()&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;转帐事务的实现&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#转帐事务的实现&#34;&gt;#&lt;/a&gt; 转帐事务的实现&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;事务添加是在业务方法中&lt;/li&gt;
&lt;li&gt;利用 try…catch 代码块，开启事务和提交事务，和事务回滚&lt;/li&gt;
&lt;li&gt;将 connection 传入 Dao，只负责使用不用关闭&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-mysql&#34;&gt;CREATE TABLE t_bank(
id INT PRIMARY KEY AUTO_INCREMENT COMMENT &#39;账号主键&#39;,
account VARCHAR(20) NOT NULL UNIQUE COMMENT &#39;账号&#39;,
money INT UNSIGNED COMMENT &#39;金额，不能为负值&#39;);

INSERT INTO t_bank(account,money) VALUES (&#39;李泽言&#39;,1000),(&#39;白起&#39;,1000);
&lt;/code&gt;&lt;/pre&gt;
