ass=&#34;token class-name&#34;&gt;Integer&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt; sonMap &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;getCount&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;file&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;42&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token comment&#34;&gt;// 遍历 sonMap 把值累加到 hm 中&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token class-name&#34;&gt;Set&lt;/span&gt;&lt;span class=&#34;token generics&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;Map&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Entry&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Integer&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt; entries &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; sonMap&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;entrySet&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;44&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;Map&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Entry&lt;/span&gt;&lt;span class=&#34;token generics&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Integer&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt; entry &lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; entries&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt; key &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; entry&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;getKey&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;46&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; value &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; entry&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;getValue&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;47&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;hm&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;containsKey&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;key&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;48&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                        &lt;span class=&#34;token comment&#34;&gt;// 存在&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;49&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                        &lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; count &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; hm&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;key&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;50&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                        count &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; count &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; value&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;51&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                        hm&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;put&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;key&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; count&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;52&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;53&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                        &lt;span class=&#34;token comment&#34;&gt;// 不存在&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;54&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                        hm&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;put&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;key&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; value&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;55&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;56&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;57&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;58&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;59&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; hm&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;60&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;61&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;io流&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#io流&#34;&gt;#&lt;/a&gt; IO 流&lt;/h2&gt;
&lt;h3 id=&#34;什么是io流&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#什么是io流&#34;&gt;#&lt;/a&gt; 什么是 IO 流？&lt;/h3&gt;
&lt;p&gt;存储和读取数据的解决方案&lt;/p&gt;
&lt;p&gt;I：input		O：output&lt;/p&gt;
&lt;p&gt;流：像水流一样传输数据&lt;/p&gt;
&lt;h3 id=&#34;io流的作用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#io流的作用&#34;&gt;#&lt;/a&gt; IO 流的作用？&lt;/h3&gt;
&lt;p&gt;用于读写数据（本地文件，网络）&lt;/p&gt;
&lt;h3 id=&#34;io流按照流向可以分为哪两种流&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#io流按照流向可以分为哪两种流&#34;&gt;#&lt;/a&gt; IO 流按照流向可以分为哪两种流？&lt;/h3&gt;
&lt;p&gt;输出流：程序	-&amp;gt;	文件&lt;/p&gt;
&lt;p&gt;输入流：文件	-&amp;gt;	程序&lt;/p&gt;
&lt;h3 id=&#34;io流按照操作文件的类型可以分为哪两种流&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#io流按照操作文件的类型可以分为哪两种流&#34;&gt;#&lt;/a&gt; IO 流按照操作文件的类型可以分为哪两种流？&lt;/h3&gt;
&lt;p&gt;字节流：可以操作所有类型的文件&lt;/p&gt;
&lt;p&gt;字符流：只能操作纯文本文件&lt;/p&gt;
&lt;h3 id=&#34;什么是纯文本文件&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#什么是纯文本文件&#34;&gt;#&lt;/a&gt; 什么是纯文本文件？&lt;/h3&gt;
&lt;p&gt;用 Windows 系统自带的笔记本打开并且能读懂的文件&lt;/p&gt;
&lt;p&gt;txt 文件，md 文件，xml 文件，lrc 文件等&lt;/p&gt;
&lt;h3 id=&#34;fileoutputstream书写细节&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#fileoutputstream书写细节&#34;&gt;#&lt;/a&gt; FileOutputStream 书写细节&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;创建字节输出流对象
&lt;ul&gt;
&lt;li&gt;参数是字符串表示的路径或者 File 对象都是可以的&lt;/li&gt;
&lt;li&gt;如果文件不存在会创建一个新的文件，但是要保证父级路径是存在的&lt;/li&gt;
&lt;li&gt;如果文件已经存在，则会清空文件&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;写数据
&lt;ul&gt;
&lt;li&gt;write 方法的参数是整数，但实际上写到本地文件中的是整数在 ASCII 上对应的字符&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;释放资源
&lt;ul&gt;
&lt;li&gt;每次使用完流之后都要释放资源&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;fileoutputstream写数据的3种方式&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#fileoutputstream写数据的3种方式&#34;&gt;#&lt;/a&gt; FileOutputStream 写数据的 3 种方式&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;方法名称&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;void write(int b)&lt;/td&gt;
&lt;td&gt;一次写一个字节数据&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;void write(byte[] b)&lt;/td&gt;
&lt;td&gt;一次写一个字节数组数据&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;void write(byte[] b, int off, int len)&lt;/td&gt;
&lt;td&gt;一次写一个字节数组的部分数据&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;figcaption data-lang=&#34;java&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; &lt;span class=&#34;token import&#34;&gt;&lt;span class=&#34;token namespace&#34;&gt;java&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;io&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;FileOutputStream&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; &lt;span class=&#34;token import&#34;&gt;&lt;span class=&#34;token namespace&#34;&gt;java&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;io&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;IOException&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;ByteStreamDemo1&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; args&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;throws&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;IOException&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 创建对象&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token class-name&#34;&gt;FileOutputStream&lt;/span&gt; fos &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;FileOutputStream&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;路径&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 写出数据&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;byte&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; bytes &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;97&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;98&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;99&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;100&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;101&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;/* 参数一：数组    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;          参数二：起始索引    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;          参数三：个数&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;         */&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        fos&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;write&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;bytes&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 释放资源&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        fos&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;close&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;总结&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#总结&#34;&gt;#&lt;/a&gt; 总结&lt;/h4&gt;
&lt;h5 id=&#34;1-fileoutputstream的作用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-fileoutputstream的作用&#34;&gt;#&lt;/a&gt; 1. FileOutputStream 的作用&lt;/h5&gt;
&lt;p&gt;可以把程序中的数据写到本地文件上，是字节流的基本流&lt;/p&gt;
&lt;h5 id=&#34;2-书写步骤&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-书写步骤&#34;&gt;#&lt;/a&gt; 2. 书写步骤&lt;/h5&gt;
&lt;p&gt;创建对象，写出数据，释放资源&lt;/p&gt;
&lt;h5 id=&#34;3-三步操作的细节&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-三步操作的细节&#34;&gt;#&lt;/a&gt; 3. 三步操作的细节&lt;/h5&gt;
&lt;p&gt;创建对象：文件存在、文件不存在、追加写入&lt;/p&gt;
&lt;p&gt;写出数据：写出整数、写出字节数组、换行写&lt;/p&gt;
&lt;p&gt;释放资源：关闭通道&lt;/p&gt;
&lt;h3 id=&#34;fileinputstream书写细节&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#fileinputstream书写细节&#34;&gt;#&lt;/a&gt; FileInputStream 书写细节&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;创建字节输入流对象
&lt;ul&gt;
&lt;li&gt;如果文件不存在，就直接报错&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;读取数据
&lt;ul&gt;
&lt;li&gt;一次读一个字节，读出来的是数据在 ASCII 上对应的数字&lt;/li&gt;
&lt;li&gt;读到文件末尾，read 方法返回 - 1&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;释放资源
&lt;ul&gt;
&lt;li&gt;每次使用完流必须要释放资源&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;字节输入流循环读取&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#字节输入流循环读取&#34;&gt;#&lt;/a&gt; 字节输入流循环读取&lt;/h3&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;figcaption data-lang=&#34;java&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; &lt;span class=&#34;token import&#34;&gt;&lt;span class=&#34;token namespace&#34;&gt;java&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;io&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;FileInputStream&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; &lt;span class=&#34;token import&#34;&gt;&lt;span class=&#34;token namespace&#34;&gt;java&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;io&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;IOException&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;ByteStreamDemo2&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; args&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;throws&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;IOException&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 创建对象&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token class-name&#34;&gt;FileInputStream&lt;/span&gt; fis &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;FileInputStream&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;路径&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 循环读取&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; b&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;while&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;b &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; fis&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;read&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;!=&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token class-name&#34;&gt;System&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;out&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;char&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; b&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        fis&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;close&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;fileinputstream一次读多个字节&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#fileinputstream一次读多个字节&#34;&gt;#&lt;/a&gt; FileInputStream 一次读多个字节&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;方法名称&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;public int read()&lt;/td&gt;
&lt;td&gt;一次读一个字节数据&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public int read(byte[] buffer)&lt;/td&gt;
&lt;td&gt;一次读一个字节数组数据&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;字符集详解&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#字符集详解&#34;&gt;#&lt;/a&gt; 字符集详解&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;在计算机中，任意数据都是以二进制的形式来存储的&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;计算机中最小的存储单元是一个字节&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;ASCII 字符集中，一个英文占一个字节&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;简体中文版 Windows，默认使用 GBK 字符集&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;GBK 字符集完全兼容 ASCII 字符集&lt;/p&gt;
&lt;p&gt;一个英文占一个字节，二进制第一位是 0&lt;/p&gt;
&lt;p&gt;一个中文占两个字节，二进制高位字节的第一位是 1&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Unicode 字符集的 UTF-8 编码模式&lt;/p&gt;
&lt;p&gt;一个英文占一个字节，二进制第一位是 0，转成十进制是正数&lt;/p&gt;
&lt;p&gt;一个中文占三个字节，二进制第一位是 1，第一个字节转成十进制是负数&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;如何不产生乱码&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#如何不产生乱码&#34;&gt;#&lt;/a&gt; 如何不产生乱码？&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;不要使用字节流读取文本文件&lt;/li&gt;
&lt;li&gt;编码解码是使用同一个码表，同一个编码方式&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;java中编码的方法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#java中编码的方法&#34;&gt;#&lt;/a&gt; Java 中编码的方法&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;String 类中的方法&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;public vyte[] getBytes()&lt;/td&gt;
&lt;td&gt;使用默认方式进行编码&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public byte[] getBytes(String charsetName)&lt;/td&gt;
&lt;td&gt;使用指定方式进行编码&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;java中解码的方法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#java中解码的方法&#34;&gt;#&lt;/a&gt; Java 中解码的方法&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;String 类中的方法&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;String(byte[] bytes)&lt;/td&gt;
&lt;td&gt;使用默认方式进行解码&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;String(byte[] bytes, String charsetName)&lt;/td&gt;
&lt;td&gt;使用指定方式进行解码&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;figcaption data-lang=&#34;java&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; &lt;span class=&#34;token import&#34;&gt;&lt;span class=&#34;token namespace&#34;&gt;java&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;io&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;UnsupportedEncodingException&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; &lt;span class=&#34;token import&#34;&gt;&lt;span class=&#34;token namespace&#34;&gt;java&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;util&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;Arrays&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;CharSetDemo&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; args&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;throws&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;UnsupportedEncodingException&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 编码&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt; str &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;사랑해요&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;byte&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; bytes1 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; str&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;getBytes&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token class-name&#34;&gt;System&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;out&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;println&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;Arrays&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;toString&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;bytes1&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;byte&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; bytes2 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; str&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;getBytes&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;GBK&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token class-name&#34;&gt;System&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;out&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;println&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;Arrays&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;toString&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;bytes2&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 解码&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt; str2 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;bytes1&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token class-name&#34;&gt;System&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;out&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;println&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;str2&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt; str3 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;bytes2&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;GBK&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token class-name&#34;&gt;System&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;out&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;println&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;str3&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;filereader书写细节&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#filereader书写细节&#34;&gt;#&lt;/a&gt; FileReader 书写细节&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;创建字符输入流对象&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;构造方法&lt;/th&gt;
&lt;th&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;public FileReader(File file)&lt;/td&gt;
&lt;td&gt;创建字符输入流关联本地文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public FileReader(String pathname)&lt;/td&gt;
&lt;td&gt;创建字符输入流关联本地文件&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;细节：如果文件不存在，就直接报错&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;读取数据&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;成员方法&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;public int read()&lt;/td&gt;
&lt;td&gt;读取数据，读到末尾返回 - 1&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public int read(char[] buffer)&lt;/td&gt;
&lt;td&gt;读取多个数据，读到末尾返回 - 1&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;细节 1：按字节进行读取，遇到中文，一次读多个字节，读取后解码，返回一个整数&lt;/p&gt;
&lt;p&gt;细节 2：读到文件末尾，read 方法返回 - 1&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;释放资源&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;filewriter书写细节&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#filewriter书写细节&#34;&gt;#&lt;/a&gt; FileWriter 书写细节&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;创建字符输出流对象&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;构造方法&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;public FileWriter(File file)&lt;/td&gt;
&lt;td&gt;创建输出流关联本地文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public FileWriter(String pathname)&lt;/td&gt;
&lt;td&gt;创建输出流关联本地文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public FileWriter(File file, boolean append)&lt;/td&gt;
&lt;td&gt;创建输出流关联本地文件，续写&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public FileWriter(String pathname, boolean append)&lt;/td&gt;
&lt;td&gt;创建输出流关联本地文件，续写&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;细节 1：参数是字符串表示的路径或者 File 对象都是可以的&lt;/p&gt;
&lt;p&gt;细节 2：如果文件不存在会创建一个新的文件，但是要保证父级路径是存在的&lt;/p&gt;
&lt;p&gt;细节 3：如果文件已经存在，则会清空文件，如果不想清空可以打开续写开关&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;写数据&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;成员方法&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;void write(int c)&lt;/td&gt;
&lt;td&gt;写出一个字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;void write(String str)&lt;/td&gt;
&lt;td&gt;写出一个字符串&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;void write(String str, int off, int len)&lt;/td&gt;
&lt;td&gt;写出一个字符串的一部分&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;void write(char[] cbuf)&lt;/td&gt;
&lt;td&gt;写出一个字符数组&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;void write(char[] cbuf, int off, int len)&lt;/td&gt;
&lt;td&gt;写出字符数组的一部分&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;细节：如果 write 方法的参数是整数，实际上写到本地文件中的是整数在字符集上对应的字符&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;释放资源&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;字符流原理解析&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#字符流原理解析&#34;&gt;#&lt;/a&gt; 字符流原理解析&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;创建字符输入流对象&lt;/p&gt;
&lt;p&gt;底层：关联文件，并创建缓冲区（长度为 8192 的字节数组）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;读取数据&lt;/p&gt;
&lt;p&gt;底层：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;判断缓冲区中是否有数据可以读取&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;
&lt;p&gt;缓冲区没有数据：从文件中获取数据，装到缓冲区，每次尽可能装满缓冲区，如果文件中没有数据，返回 - 1&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;缓冲区有数据：从缓冲区中读取&lt;/p&gt;
&lt;p&gt;​		空参的 read 方法：一次读取一个字节，遇到中文一次读多个字节，把字节解码并转成十进制返回&lt;/p&gt;
&lt;p&gt;​		有参的 read 方法：把读取字节解码，强转三步合并，强转之后的字符放到数组中&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;字节流和字符流的使用场景&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#字节流和字符流的使用场景&#34;&gt;#&lt;/a&gt; 字节流和字符流的使用场景&lt;/h3&gt;
&lt;p&gt;字节流：拷贝任意类型的文件&lt;/p&gt;
&lt;p&gt;字符流：读取纯文本文件中的数据&lt;/p&gt;
&lt;p&gt;​				往纯文本文件中写出数据&lt;/p&gt;
&lt;h3 id=&#34;字节缓冲流&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#字节缓冲流&#34;&gt;#&lt;/a&gt; 字节缓冲流&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;方法名称&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;public BufferedInputStream(InputStream is)&lt;/td&gt;
&lt;td&gt;把基本流包装成高级流，提高读取数据的性能&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public BufferedOutputStream(OutputStream os)&lt;/td&gt;
&lt;td&gt;把基本流包装成高级流，提高写出数据的性能&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;字符缓冲流&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#字符缓冲流&#34;&gt;#&lt;/a&gt; 字符缓冲流&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;方法名称&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;public BufferedReader(Reader r)&lt;/td&gt;
&lt;td&gt;把基本流变成高级流&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public BufferedWriter(Writer r)&lt;/td&gt;
&lt;td&gt;把基本流变成高级流&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;字符缓冲输入流特有方法&lt;/td&gt;
&lt;td&gt;说明&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;--------------------------&lt;/td&gt;
&lt;td&gt;------------------------------------------&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public String readLine()&lt;/td&gt;
&lt;td&gt;读取一行数据，如果没有数据可读，会返回 null&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;字符缓冲输出流特有方法&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;&lt;strong&gt;说明&lt;/strong&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public void newLine()&lt;/td&gt;
&lt;td&gt;跨平台的换行&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h4 id=&#34;总结-2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#总结-2&#34;&gt;#&lt;/a&gt; 总结&lt;/h4&gt;
&lt;h5 id=&#34;1-缓冲流有几种&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-缓冲流有几种&#34;&gt;#&lt;/a&gt; 1. 缓冲流有几种？&lt;/h5&gt;
&lt;ul&gt;
&lt;li&gt;字节缓冲输入流：BufferedInputStream&lt;/li&gt;
&lt;li&gt;字节缓冲输出流：BufferedOutputStream&lt;/li&gt;
&lt;li&gt;字符缓冲输入流：BufferedReader&lt;/li&gt;
&lt;li&gt;字符缓冲输出流：BufferedWriter&lt;/li&gt;
&lt;/ul&gt;
&lt;h5 id=&#34;2-缓冲流为什么能提高性能&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-缓冲流为什么能提高性能&#34;&gt;#&lt;/a&gt; 2. 缓冲流为什么能提高性能&lt;/h5&gt;
&lt;ul&gt;
&lt;li&gt;缓冲流自带长度 8192 的缓冲区&lt;/li&gt;
&lt;li&gt;可以显著提高字节流的读写性能&lt;/li&gt;
&lt;li&gt;对于字符流提升不明显，对于字符缓冲流而言关键点是两个特有的方法&lt;/li&gt;
&lt;/ul&gt;
&lt;h5 id=&#34;3-字符缓冲流两个特有的方法是什么&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-字符缓冲流两个特有的方法是什么&#34;&gt;#&lt;/a&gt; 3. 字符缓冲流两个特有的方法是什么？&lt;/h5&gt;
&lt;ul&gt;
&lt;li&gt;字符缓冲输入流 BufferedReader：readLine ()&lt;/li&gt;
&lt;li&gt;字符缓冲输出流 BufferedWriter：newLine ()&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;转换流&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#转换流&#34;&gt;#&lt;/a&gt; 转换流&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;转换流的名字是什么？&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;字符转换输入流：InputStreamReader&lt;/li&gt;
&lt;li&gt;字符转换输出流：OutputStreamWriter&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;转换流的作用是什么？&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;指定字符集读写数据（JDK11 之后已淘汰）&lt;/li&gt;
&lt;li&gt;字节流想要使用字符流中的方法&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;序列化流&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#序列化流&#34;&gt;#&lt;/a&gt; 序列化流&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;可以把 Java 中的对象写到本地文件中&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;构造方法&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;public ObjectOutputStream(OutputStream out)&lt;/td&gt;
&lt;td&gt;把基本流包装成高级流&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;成员方法&lt;/td&gt;
&lt;td&gt;说明&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;-----------------------------------------&lt;/td&gt;
&lt;td&gt;------------------------------&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public final void writeObject(Object obj)&lt;/td&gt;
&lt;td&gt;把对象序列化（写出）到文件中去&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;反序列化流&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#反序列化流&#34;&gt;#&lt;/a&gt; 反序列化流&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;可以把序列化到本地文件中的对象，读取到程序中来&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;构造方法&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;public ObjectInputStream(InputStream out)&lt;/td&gt;
&lt;td&gt;把基本流变成高级流&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;成员方法&lt;/td&gt;
&lt;td&gt;说明&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;--------------------------&lt;/td&gt;
&lt;td&gt;------------------------------------------&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public Object readObject()&lt;/td&gt;
&lt;td&gt;把序列化到本地文件中的对象，读取到程序中来&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;序列化流反序列化流细节&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#序列化流反序列化流细节&#34;&gt;#&lt;/a&gt; 序列化流 / 反序列化流细节&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;使用序列化流将对象写到文件时，需要让 Javabean 类实现 Serializable 接口。否则，会出现 NotSerializableException 异常&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;序列化流写到文件中的数据时不能修改的，一旦修改就无法再次读回&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;序列化对象后，修改了 Javabean 类，再次反序列化，会不会有问题？&lt;/p&gt;
&lt;p&gt;会出问题，会抛出 InvalidClassException 异常&lt;/p&gt;
&lt;p&gt;解决方案：给 Javabean 类添加 serialVersionUID（序列号、版本号）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;如果一个对象中的某个成员变量的值不想被序列化，该如何实现？&lt;/p&gt;
&lt;p&gt;解决方案：给该成员变量加 transient 关键字修饰，该关键字标记的成员变量不参与序列化过程&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;打印流&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#打印流&#34;&gt;#&lt;/a&gt; 打印流&lt;/h3&gt;
&lt;h4 id=&#34;分类&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#分类&#34;&gt;#&lt;/a&gt; 分类&lt;/h4&gt;
&lt;p&gt;打印流一般指 PrintStream，PrintWrite 两个类&lt;/p&gt;
&lt;h4 id=&#34;特点&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#特点&#34;&gt;#&lt;/a&gt; 特点&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;打印流只操作文件目的地，不操作数据源&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;特有的写出方法可以实现，数据原样写出&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;特有的写出方法，可以实现自动刷新，自动换行&lt;/p&gt;
&lt;p&gt;打印一次数据 = 写出 + 换行 + 刷新&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;构造方法&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;public PrintStream(OutputStream/File/String)&lt;/td&gt;
&lt;td&gt;关联字节输出流 / 文件 / 文件路径&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public PrintStream(String fileName, Charset charset)&lt;/td&gt;
&lt;td&gt;指定字符编码&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public PrintStream(OutputStream out, boolean autoFlush)&lt;/td&gt;
&lt;td&gt;自动刷新&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public PringStream(OutputStream out, boolean autoFlush, String encoding)&lt;/td&gt;
&lt;td&gt;指定字符编码且自动刷新&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;成员方法&lt;/td&gt;
&lt;td&gt;说明&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;-------------------------------------------------&lt;/td&gt;
&lt;td&gt;------------------------------------------&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public void write(int b)&lt;/td&gt;
&lt;td&gt;常规方法：将指定的字节写出&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public void println(Xxx xx)&lt;/td&gt;
&lt;td&gt;特有方法：打印任意数据，自动刷新，自动换行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public void print(Xxx xx)&lt;/td&gt;
&lt;td&gt;特有方法：打印任意数据，不换行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public void printf(String format, Object… args)&lt;/td&gt;
&lt;td&gt;特有方法：带有占位符的打印语句，不换行&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h4 id=&#34;总结-3&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#总结-3&#34;&gt;#&lt;/a&gt; 总结&lt;/h4&gt;
&lt;p&gt;打印流有几种？各有什么特点？&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;有字节打印流和字符打印流两种&lt;/li&gt;
&lt;li&gt;打印流不操作数据源，只能操作目的地&lt;/li&gt;
&lt;li&gt;字节打印流：默认自动刷新，特有的 println 自动换行&lt;/li&gt;
&lt;li&gt;字符打印流：自动刷新需要开启，特有的 println 自动换行&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;解压缩流&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#解压缩流&#34;&gt;#&lt;/a&gt; 解压缩流&lt;/h3&gt;
&lt;p&gt;解压本质：把每一个 ZipEntry 按照层级拷贝到本地另一个文件夹中&lt;/p&gt;
&lt;h3 id=&#34;commons-io&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#commons-io&#34;&gt;#&lt;/a&gt; Commons-io&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;FileUtils 类（文件 / 文件夹相关）&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;static void copyFile(File srcFile, File destFile)&lt;/td&gt;
&lt;td&gt;复制文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;static void copyDirectory(File srcDir, File destDir)&lt;/td&gt;
&lt;td&gt;复制文件夹&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;static void copyDirectoryToDirectory(File srcDir, File destDir)&lt;/td&gt;
&lt;td&gt;复制文件夹&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;static void deleteDirectory(File directory)&lt;/td&gt;
&lt;td&gt;删除文件夹&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;static void cleanDirectory(File directory)&lt;/td&gt;
&lt;td&gt;清空文件夹&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;static String readFileToString(File file, Charset encoding)&lt;/td&gt;
&lt;td&gt;读取文件中的数据变成字符串&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;static void write(File file, CharSequence data, String encoding)&lt;/td&gt;
&lt;td&gt;写出数据&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;IOUtils 类（流相关）&lt;/td&gt;
&lt;td&gt;说明&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;------------------------------------------------------------&lt;/td&gt;
&lt;td&gt;----------&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public static int copy(InputStream input, OutputStream output)&lt;/td&gt;
&lt;td&gt;复制文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public static int copyLarge(Reader input, Writer output)&lt;/td&gt;
&lt;td&gt;复制大文件&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public static String readLines(Reader input)&lt;/td&gt;
&lt;td&gt;读取数据&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public static void write(String data, OutputStream output)&lt;/td&gt;
&lt;td&gt;写出数据&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;hutool工具包&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#hutool工具包&#34;&gt;#&lt;/a&gt; Hutool 工具包&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;相关类&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;IoUtil&lt;/td&gt;
&lt;td&gt;流操作工具类&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;FileUtil&lt;/td&gt;
&lt;td&gt;文件读写和操作的工具类&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;FileTypeUtil&lt;/td&gt;
&lt;td&gt;文件类型判断工具类&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;WatchMonitor&lt;/td&gt;
&lt;td&gt;目录、文件监听&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;ClassPathResource&lt;/td&gt;
&lt;td&gt;针对 ClassPath 中资源的访问封装&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;FileReader&lt;/td&gt;
&lt;td&gt;封装文件读取&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;FileWriter&lt;/td&gt;
&lt;td&gt;封装文件写入&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;多线程&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#多线程&#34;&gt;#&lt;/a&gt; 多线程&lt;/h2&gt;
&lt;h3 id=&#34;线程&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#线程&#34;&gt;#&lt;/a&gt; 线程&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;线程是操作系统能够进行运算调度的最小单位。它被包含在进程中，是进程的实际运作单位&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;什么是多线程？&lt;/p&gt;
&lt;p&gt;有了多线程，可以让程序同时做多件事情&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;多线程的作用？&lt;/p&gt;
&lt;p&gt;提高效率&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;多线程应用场景？&lt;/p&gt;
&lt;p&gt;只要想让多个事情同时运行就需要用到多线程&lt;/p&gt;
&lt;p&gt;比如：软件中的耗时操作、所有的聊天软件、所有的服务器&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;并发和并行&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#并发和并行&#34;&gt;#&lt;/a&gt; 并发和并行&lt;/h3&gt;
&lt;p&gt;并发：在同一时刻，有多个指令在单个 CPU 上交替进行&lt;/p&gt;
&lt;p&gt;并行：在同一时刻，有多个指令在多个 CPU 上同时进行&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;多线程三种实现方式对比&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;&lt;/th&gt;
&lt;th&gt;优点&lt;/th&gt;
&lt;th&gt;缺点&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;继承 Thread 类&lt;/td&gt;
&lt;td&gt;编程比较简单，可以直接使用 Thread 类中的方法&lt;/td&gt;
&lt;td&gt;可以扩展性较差，不能再继承其他的类&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;实现 Runnable 接口&lt;/td&gt;
&lt;td&gt;扩展性强，实现该接口的同时还可以继承其他的类&lt;/td&gt;
&lt;td&gt;编程相对复杂，不能直接使用 Thread 类中的方法&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;实现 Callable 接口&lt;/td&gt;
&lt;td&gt;同上&lt;/td&gt;
&lt;td&gt;同上&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ul&gt;
&lt;li&gt;常见的成员方法&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;方法名称&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;String getName()&lt;/td&gt;
&lt;td&gt;返回此线程的名称&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;void setName(String name)&lt;/td&gt;
&lt;td&gt;设置线程的名字（构造方法也可以设置名字）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;static&lt;/strong&gt; Thread currentThread()&lt;/td&gt;
&lt;td&gt;获取当前线程的对象&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;static&lt;/strong&gt; void sleep(long time)&lt;/td&gt;
&lt;td&gt;让线程休眠指定的时间，单位为毫秒&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;setPriority(int newPriority)&lt;/td&gt;
&lt;td&gt;设置线程的优先级&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;final int getPriority()&lt;/td&gt;
&lt;td&gt;获取线程的优先级&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;final void setDaemon(boolean on)&lt;/td&gt;
&lt;td&gt;设置为守护线程&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public static void yield()&lt;/td&gt;
&lt;td&gt;出让线程 / 礼让线程&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public static void join()&lt;/td&gt;
&lt;td&gt;插入线程 / 插队线程&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;线程的生命周期&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#线程的生命周期&#34;&gt;#&lt;/a&gt; 线程的生命周期&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;https://xingqiu-tuchuang-1256524210.cos.ap-shanghai.myqcloud.com/12967/Snipaste_2023-02-17_14-23-31.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;线程状态&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#线程状态&#34;&gt;#&lt;/a&gt; 线程状态&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;https://xingqiu-tuchuang-1256524210.cos.ap-shanghai.myqcloud.com/12967/Snipaste_2023-02-17_16-15-26.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;线程池&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#线程池&#34;&gt;#&lt;/a&gt; 线程池&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;Executors：线程池的工具类通过调用方法返回不同类型的线程池对象&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;方法名称&lt;/th&gt;
&lt;th&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;public static ExecutorService newCachedThreadPool()&lt;/td&gt;
&lt;td&gt;创建一个没有上限的线程池&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;public static ExecutorService newFixedThreadPool(int nThreads)&lt;/td&gt;
&lt;td&gt;创建有上限的的线程池&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h4 id=&#34;主要核心原理&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#主要核心原理&#34;&gt;#&lt;/a&gt; 主要核心原理&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;创建一个池子，池子中是空的&lt;/li&gt;
&lt;li&gt;提交任务时，池子会创建新的线程对象，任务执行完毕，线程归还给池子，下回再次提交任务时，不需要创建新的线程，直接复用已有的线程即可&lt;/li&gt;
&lt;li&gt;如果提交任务时，池子中没有空闲线程，也无法创建新的线程，任务就会排队等待&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;自定义线程池&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#自定义线程池&#34;&gt;#&lt;/a&gt; 自定义线程池&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;创建一个空的池子&lt;/li&gt;
&lt;li&gt;有任务提交时，线程池会创建线程去执行任务，执行完毕归还线程&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;不断的提交任务会有以下三个临界点&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#不断的提交任务会有以下三个临界点&#34;&gt;#&lt;/a&gt; 不断的提交任务，会有以下三个临界点：&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;当核心线程满时，再提交任务就会排队&lt;/li&gt;
&lt;li&gt;当核心线程满，队伍满时，会创建临时线程&lt;/li&gt;
&lt;li&gt;当核心线程满，队伍满，临时线程满时，会触发任务拒绝策略&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;CPU 密集型运算：最大并行数 + 1&lt;/li&gt;
&lt;li&gt;I/O 密集型运算：最大并行数 * 期望 CPU 利用率 * (总时间 (CPU 计算时间 + 等待时间)) / CPU 计算时间&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;网络编程&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#网络编程&#34;&gt;#&lt;/a&gt; 网络编程&lt;/h2&gt;
&lt;h3 id=&#34;初识网络编程&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#初识网络编程&#34;&gt;#&lt;/a&gt; 初识网络编程&lt;/h3&gt;
&lt;h4 id=&#34;1-什么是网络编程&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-什么是网络编程&#34;&gt;#&lt;/a&gt; 1. 什么是网络编程？&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;计算机跟计算机之间通过网络进行数据传输&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;2-常见软件架构有哪些&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-常见软件架构有哪些&#34;&gt;#&lt;/a&gt; 2. 常见软件架构有哪些？&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;CS/BS&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;3-通信的软件架构csbs各有什么区别和优缺点&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-通信的软件架构csbs各有什么区别和优缺点&#34;&gt;#&lt;/a&gt; 3. 通信的软件架构 CS/BS 各有什么区别和优缺点？&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;CS：客户端服务端模式需要开发客户端&lt;/li&gt;
&lt;li&gt;BS：浏览器服务端模式不需要开发客户端&lt;/li&gt;
&lt;li&gt;CS：适合定制专业化的办公类软件，如：IDEA、网游&lt;/li&gt;
&lt;li&gt;BS：适合移动互联网应用，可以在任何地方随时访问的系统&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;网络编程三要素&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#网络编程三要素&#34;&gt;#&lt;/a&gt; 网络编程三要素&lt;/h3&gt;
&lt;h4 id=&#34;1-网络编程三要素分别是什么&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-网络编程三要素分别是什么&#34;&gt;#&lt;/a&gt; 1. 网络编程三要素分别是什么？&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;IP、端口号、协议&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;2-网络编程三要素分别表示什么&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-网络编程三要素分别表示什么&#34;&gt;#&lt;/a&gt; 2. 网络编程三要素分别表示什么？&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;IP：设备在网络中的地址，是唯一的标识&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;端口号：应用程序在设备中唯一的标识&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;协议：数据在网络中传输的规则&lt;/p&gt;
&lt;p&gt;​			常见的协议有 UDP、TCP、http、https、ftp&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;ip&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#ip&#34;&gt;#&lt;/a&gt; IP&lt;/h3&gt;
&lt;h4 id=&#34;1-ip的作用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-ip的作用&#34;&gt;#&lt;/a&gt; 1. IP 的作用&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;设备在网络中的地址，是唯一的标识&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;2-ipv4特点&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-ipv4特点&#34;&gt;#&lt;/a&gt; 2. IPv4 特点&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;目前的主流方案&lt;/li&gt;
&lt;li&gt;最多只有 2^32 次方个 IP，目前已经用完&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;3-ipv6特点&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-ipv6特点&#34;&gt;#&lt;/a&gt; 3. IPv6 特点&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;为了解决 IPv4 不够用而出现&lt;/li&gt;
&lt;li&gt;最多有 2^128 次方个 IP&lt;/li&gt;
&lt;li&gt;可以为地球上的每一粒沙子都设定 IP&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;ipv4&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#ipv4&#34;&gt;#&lt;/a&gt; IPv4&lt;/h3&gt;
&lt;h4 id=&#34;1-如何解决ipv4不够的问题&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-如何解决ipv4不够的问题&#34;&gt;#&lt;/a&gt; 1. 如何解决 IPv4 不够的问题&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;利用局域网 IP 解决 IP 不够的问题&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;2-特殊的ip是什么&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-特殊的ip是什么&#34;&gt;#&lt;/a&gt; 2. 特殊的 IP 是什么？&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;127.0.0.1（永远表示主机）&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;3-常见的两个cmd命令&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-常见的两个cmd命令&#34;&gt;#&lt;/a&gt; 3. 常见的两个 CMD 命令&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;ipconfig：查看本机 IP 地址&lt;/li&gt;
&lt;li&gt;ping：检查网络是否连通&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;端口号&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#端口号&#34;&gt;#&lt;/a&gt; 端口号&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;应用程序在设备中的唯一的标识&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;端口号：由两个字节表示的整数，取值范围：0~65535&lt;/p&gt;
&lt;p&gt;​				其中 0~1023 之间的端口号用于一些知名的网络服务或者应用&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;一个端口号只能被一个应用程序使用&lt;/strong&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;协议&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#协议&#34;&gt;#&lt;/a&gt; 协议&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;计算机网络中，连接和通信的规则被称为网络通信协议&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;udp协议&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#udp协议&#34;&gt;#&lt;/a&gt; UDP 协议&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;用户数据报协议（User Datagram Protocol）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;UDP 是&lt;strong&gt;面向无连接&lt;/strong&gt;通信协议&lt;/p&gt;
&lt;p&gt;速度快，有大小限制一次最多发送 64K，数据不安全，易丢失数据&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;tcp协议&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#tcp协议&#34;&gt;#&lt;/a&gt; TCP 协议&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;传输控制协议（Transmission Control Protocol）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;TCP 协议是&lt;strong&gt;面向连接&lt;/strong&gt;通信协议&lt;/p&gt;
&lt;p&gt;速度慢，没有大小限制，数据安全&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;三次握手四次挥手&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#三次握手四次挥手&#34;&gt;#&lt;/a&gt; 三次握手四次挥手&lt;/h3&gt;
&lt;h4 id=&#34;三次握手&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#三次握手&#34;&gt;#&lt;/a&gt; 三次握手&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;客户端向服务器发出连接请求，等待服务器确认&lt;/li&gt;
&lt;li&gt;服务器向客户端返回一个响应，告诉客户端收到了请求&lt;/li&gt;
&lt;li&gt;客户端向服务器再次发出确认信息，连接建立&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;四次挥手&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#四次挥手&#34;&gt;#&lt;/a&gt; 四次挥手&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;客户端向服务器发出取消连接请求&lt;/li&gt;
&lt;li&gt;服务器向客户端返回一个响应，表示收到客户端取消请求&lt;/li&gt;
&lt;li&gt;服务器向客户端发出确认取消信息&lt;/li&gt;
&lt;li&gt;客户端再次发送确认信息，连接取消&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;反射&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#反射&#34;&gt;#&lt;/a&gt; 反射&lt;/h2&gt;
&lt;h3 id=&#34;概述&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#概述&#34;&gt;#&lt;/a&gt; 概述&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;反射允许对成员变量，成员方法和构造方法的信息进行编程访问&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;代码实现&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#代码实现&#34;&gt;#&lt;/a&gt; 代码实现&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;全类名：包名 + 类名&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;figcaption data-lang=&#34;java&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token class-name&#34;&gt;Class&lt;/span&gt; clazz1 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Class&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;forName&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;更多的是当作参数进行传递&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;figcaption data-lang=&#34;java&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token class-name&#34;&gt;Class&lt;/span&gt; clazz2 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Student&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;class&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;当已经有了这个类的对象时，才可以使用&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;figcaption data-lang=&#34;java&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token class-name&#34;&gt;Student&lt;/span&gt; s &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Student&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token class-name&#34;&gt;Class&lt;/span&gt; clazz3 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; s&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;getClass&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;反射获取成员变量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#反射获取成员变量&#34;&gt;#&lt;/a&gt; 反射获取成员变量&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Class 类中用于获取成员变量的方法&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;Field[] getFields()&lt;/td&gt;
&lt;td&gt;返回所有公共成员变量对象的数组&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Field[] getDeclaredFields()&lt;/td&gt;
&lt;td&gt;返回所有成员变量对象的数组&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Field getField(String name)&lt;/td&gt;
&lt;td&gt;返回单个公共成员变量对象&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Field getDeclaredField(String name)&lt;/td&gt;
&lt;td&gt;返回单个成员变量对象&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;Field 类中用于创建对象的方法&lt;/td&gt;
&lt;td&gt;说明&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;----------------------------------&lt;/td&gt;
&lt;td&gt;------&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;void set(Object obj, Object value)&lt;/td&gt;
&lt;td&gt;赋值&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Object get(Object obj)&lt;/td&gt;
&lt;td&gt;获取值&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;反射获取成员方法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#反射获取成员方法&#34;&gt;#&lt;/a&gt; 反射获取成员方法&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Class 类中用于获取成员方法的方法&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;Method[] getMethod()&lt;/td&gt;
&lt;td&gt;返回所有公共成员方法对象的数组，包括继承的&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Method[] getDeclaredMethods()&lt;/td&gt;
&lt;td&gt;返回所有成员方法对象的数组，不包括继承的&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Method getMethod(String name, Class&amp;lt;?&amp;gt;… parameterTypes)&lt;/td&gt;
&lt;td&gt;返回单个公共成员方法对象&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Method getDeclaredMethod(String name, Class&amp;lt;?&amp;gt;… parameterTypes)&lt;/td&gt;
&lt;td&gt;返回但各成员方法对象&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;Method 类中用于创建对象的方法&lt;/td&gt;
&lt;td&gt;说明&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;-----------------------------------------&lt;/td&gt;
&lt;td&gt;--------&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Object invoke(Object obj, Object… args)&lt;/td&gt;
&lt;td&gt;运行方法&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ul&gt;
&lt;li&gt;参数一：用 obj 对象调用该方法&lt;/li&gt;
&lt;li&gt;参数二：调用方法的传递的参数（如果没有就不写）&lt;/li&gt;
&lt;li&gt;返回值：方法的返回值（如果没有就不写）&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;动态代理&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#动态代理&#34;&gt;#&lt;/a&gt; 动态代理&lt;/h2&gt;
&lt;h3 id=&#34;动态代理思想分析&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#动态代理思想分析&#34;&gt;#&lt;/a&gt; 动态代理思想分析&lt;/h3&gt;
&lt;h4 id=&#34;1-为什么需要代理&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-为什么需要代理&#34;&gt;#&lt;/a&gt; 1. 为什么需要代理？&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;代理可以无侵入式的给对象增强其他的功能&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img data-src=&#34;https://xingqiu-tuchuang-1256524210.cos.ap-shanghai.myqcloud.com/12967/Snipaste_2023-02-27_13-16-31.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;2-代理长什么样&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-代理长什么样&#34;&gt;#&lt;/a&gt; 2. 代理长什么样？&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;代理里面就是对象要被代理的方法&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;3-java通过什么来保证代理的样子&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-java通过什么来保证代理的样子&#34;&gt;#&lt;/a&gt; 3. Java 通过什么来保证代理的样子？&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;通过接口保证，后面的对象和代理需要实现同一个接口，接口中就是被代理的所有方法&lt;/li&gt;
&lt;/ul&gt;
